mapper.select:
SELECT id, year, title, summary, image_url
FROM t_event
WHERE month = #{month}
  AND day = #{day}
ORDER BY year ASC
LIMIT 5

SELECT id, title, year, month, day, summary, content, image_url, tags, source
FROM t_event
WHERE id = #{id}

SELECT id, title, year, month, day, summary, content, image_url, tags, source
FROM t_event
WHERE id != #{eventId}

    AND (

        title LIKE CONCAT('%', #{keyword}, '%')
        OR summary LIKE CONCAT('%', #{keyword}, '%')
        OR tags LIKE CONCAT('%', #{keyword}, '%')

    )

ORDER BY year DESC, id DESC
LIMIT #{limit}

SELECT id, title, year, month, day, summary, content, image_url, tags, source
FROM t_event
WHERE id != #{eventId}
ORDER BY ABS(year - #{year}) ASC, id DESC
LIMIT #{limit}

mapper.update:
UPDATE t_event
SET image_url = #{imageUrl}
WHERE id = #{id}
